import { useState } from 'react';

// Child: displays data, calls back when the user acts
function Counter({ count, onIncrement }) {
  return (
    <div>
      <p>Count: {count}</p>
      <button onClick={onIncrement}>+1</button>
    </div>
  );
}

// Parent: owns the state
function App() {
  const [count, setCount] = useState(0);

  return (
    <Counter
      count={count}                         // data flows DOWN
      onIncrement={() => setCount(c => c + 1)} // callback flows DOWN; event fires UP
    />
  );
}

function SearchBox({ query, onQueryChange }) {
  return (
    <input
      type="search"
      value={query}                              // data DOWN
      onChange={e => onQueryChange(e.target.value)}  // event UP
    />
  );
}

function SearchPage() {
  const [query, setQuery] = useState('');
  const results = useSearchResults(query);

  return (
    <div>
      <SearchBox
        query={query}              // data flows down
        onQueryChange={setQuery}   // callback flows down; event fires up
      />
      <SearchResults results={results} />
    </div>
  );
}

// Both panels need to know which tab is active.
// If it lived in TabBar, TabContent wouldn't receive it.
// If it lived in TabContent, TabBar couldn't change it.
// Solution: lift to their parent.

function TabbedView({ tabs }) {
  const [activeIndex, setActiveIndex] = useState(0);  // lifted state

  return (
    <div>
      <TabBar
        tabs={tabs}
        activeIndex={activeIndex}      // data flows down to TabBar
        onSelect={setActiveIndex}      // callback flows down
      />
      <TabContent                      // data flows down to TabContent
        content={tabs[activeIndex].content}
      />
    </div>
  );
}

function TabBar({ tabs, activeIndex, onSelect }) {
  return (
    <nav>
      {tabs.map((tab, i) => (
        <button
          key={tab.id}
          aria-selected={activeIndex === i}
          onClick={() => onSelect(i)}   // fires event up
        >
          {tab.label}
        </button>
      ))}
    </nav>
  );
}

function TabContent({ content }) {
  return <div>{content}</div>;
}

// ❌ Wrong — mutating the prop directly
function BadCounter({ count }) {
  return (
    <button onClick={() => { count++; }}>  {/* count is a primitive copy, this does nothing visible */}
      {count}
    </button>
  );
}

// ❌ Also wrong — mutating an object prop
function BadList({ items }) {
  // This mutates the parent's array!
  items.push({ id: Date.now(), text: 'New item' });
  return <ul>{items.map(i => <li key={i.id}>{i.text}</li>)}</ul>;
}

// ✓ Correct — signal the parent
function GoodList({ items, onAdd }) {
  return (
    <>
      <button onClick={() => onAdd({ id: Date.now(), text: 'New item' })}>Add</button>
      <ul>{items.map(i => <li key={i.id}>{i.text}</li>)}</ul>
    </>
  );
}

// user is drilled through Layout and Sidebar without either using it:
function App() {
  const user = useCurrentUser();
  return <Layout user={user} />;
}

function Layout({ user }) {
  return <Sidebar user={user} />;   // Layout doesn't use user
}

function Sidebar({ user }) {
  return <UserBadge user={user} />;  // Sidebar doesn't use user
}

function UserBadge({ user }) {
  return <img src={user.photo} alt={user.name} />;  // only UserBadge uses it
}

function Parent() {
  const [x, setX] = useState(0);
  const [y, setY] = useState(0);

  // When x changes:
  // - Parent re-renders
  // - ChildA re-renders (receives new x prop)
  // - ChildB re-renders too (even though its y prop hasn't changed)
  //   unless it is wrapped in React.memo

  return (
    <>
      <ChildA value={x} />
      <ChildB value={y} />
      <button onClick={() => setX(x + 1)}>Change x</button>
    </>
  );
}

// React.memo stops ChildB re-rendering when only x changes:
const ChildB = React.memo(function ChildB({ value }) {
  return <p>{value}</p>;
});

// useReducer is React's built-in Flux/Redux for component-local state
import { useReducer } from 'react';

function postsReducer(state, action) {
  switch (action.type) {
    case 'LIKE_POST':
      return state.map(post =>
        post.id === action.postId
          ? { ...post, likes: post.likes + 1 }  // new object, no mutation
          : post
      );
    case 'ADD_POST':
      return [...state, action.post];  // new array, no mutation
    default:
      return state;
  }
}

function PostsApp({ initialPosts }) {
  const [posts, dispatch] = useReducer(postsReducer, initialPosts);

  return (
    <div>
      {posts.map(post => (
        <PostCard
          key={post.id}
          post={post}                                             // data DOWN
          onLike={() => dispatch({ type: 'LIKE_POST', postId: post.id })} // event UP
        />
      ))}
    </div>
  );
}

// ❌ Mutation — React won't detect the change because the reference is the same
function buggyUpdate(setList) {
  return function(item) {
    setList(prev => {
      prev.push(item);   // mutates the previous array
      return prev;       // returns the SAME reference — React sees no change
    });
  };
}

// ✓ Immutable update — new array, new reference, React detects the change
function correctUpdate(setList) {
  return function(item) {
    setList(prev => [...prev, item]);  // spread creates a new array
  };
}

// The same principle applies to objects:
// ❌ Don't do this:
setUser(prev => { prev.name = 'Alice'; return prev; });
// ✓ Do this:
setUser(prev => ({ ...prev, name: 'Alice' }));

function ShopPage() {
  const [cartItems, setCartItems] = useState([]);

  const addToCart    = (product) => setCartItems(prev => [...prev, { ...product, qty: 1 }]);
  const removeFromCart = (id) => setCartItems(prev => prev.filter(i => i.id !== id));
  const updateQty    = (id, qty) =>
    setCartItems(prev => prev.map(i => i.id === id ? { ...i, qty } : i));

  return (
    <div className="shop-layout">
      {/* ProductGrid only needs addToCart — it never sees cartItems */}
      <ProductGrid onAddToCart={addToCart} />

      {/* CartPanel needs to display and modify items */}
      <CartPanel
        items={cartItems}           // data DOWN
        onRemove={removeFromCart}   // callback DOWN → event UP
        onUpdateQty={updateQty}     // callback DOWN → event UP
      />
    </div>
  );
}

function CartPanel({ items, onRemove, onUpdateQty }) {
  const total = items.reduce((sum, i) => sum + i.price * i.qty, 0);
  return (
    <aside>
      <ul>
        {items.map(item => (
          <CartItem
            key={item.id}
            item={item}
            onRemove={() => onRemove(item.id)}
            onQtyChange={qty => onUpdateQty(item.id, qty)}
          />
        ))}
      </ul>
      <p>Total: ${total.toFixed(2)}</p>
    </aside>
  );
}
